@dataclass
class MultiProfileConfig:
    &quot;&quot;&quot;Configuration for multi-profile routing within a single Gateway.

    When ``enabled`` is True, the Gateway resolves an active profile per
    incoming message via the ``profile_bindings`` table.  When False (the
    default), the Gateway uses its own INTELLECT_HOME for every message —
    the pre-v0.2.0 single-profile behaviour.
    &quot;&quot;&quot;
    enabled: bool = False
    # Fallback profile name when no binding matches (default: &quot;default&quot;).
    # Must correspond to a directory under ~/.intellect/profiles/&lt;name&gt;/.
    default_profile: str = &quot;default&quot;
    # Maximum number of AIAgent instances cached per profile.
    agent_cache_max_size: int = 128
    # Seconds of idle time before a per-profile agent is evicted.
    agent_cache_idle_ttl_secs: float = 3600.0

    def to_dict(self) -&gt; Dict[str, Any]:
        return {
            &quot;enabled&quot;: self.enabled,
            &quot;default_profile&quot;: self.default_profile,
            &quot;agent_cache_max_size&quot;: self.agent_cache_max_size,
            &quot;agent_cache_idle_ttl_secs&quot;: self.agent_cache_idle_ttl_secs,
        }

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -&gt; &quot;MultiProfileConfig&quot;:
        if not data:
            return cls()
        return cls(
            enabled=_coerce_bool(data.get(&quot;enabled&quot;), False),
            default_profile=data.get(&quot;default_profile&quot;, &quot;default&quot;),
            agent_cache_max_size=_coerce_int(data.get(&quot;agent_cache_max_size&quot;), 128),
            agent_cache_idle_ttl_secs=_coerce_float(
                data.get(&quot;agent_cache_idle_ttl_secs&quot;), 3600.0
            ),
        )
