def set_profile_binding(
    self, platform: str, scope: str, scope_value: str, profile_name: str
) -&gt; None:
    &quot;&quot;&quot;Bind a user or chat to a profile.&quot;&quot;&quot;
    def _do(conn):
        conn.execute(
            &quot;INSERT OR REPLACE INTO profile_bindings &quot;
            &quot;(platform, scope, scope_value, profile_name, created_at) &quot;
            &quot;VALUES (?, ?, ?, ?, unixepoch())&quot;,
            (platform, scope, scope_value, profile_name),
        )
    self._execute_write(_do)

def get_profile_binding(
    self, platform: str, scope: str, scope_value: str
) -&gt; Optional[str]:
    &quot;&quot;&quot;Return the profile_name bound to this user/chat, or None.&quot;&quot;&quot;
    try:
        cur = self._conn.execute(
            &quot;SELECT profile_name FROM profile_bindings &quot;
            &quot;WHERE platform = ? AND scope = ? AND scope_value = ?&quot;,
            (platform, scope, scope_value),
        )
        row = cur.fetchone()
        return row[&quot;profile_name&quot;] if row else None
    except Exception:
        return None

def list_profile_bindings(self) -&gt; List[Dict[str, Any]]:
    &quot;&quot;&quot;Return all profile bindings, newest first.&quot;&quot;&quot;
    try:
        cur = self._conn.execute(
            &quot;SELECT * FROM profile_bindings ORDER BY created_at DESC&quot;
        )
        return [dict(r) for r in cur.fetchall()]
    except Exception:
        return []

def delete_profile_binding(
    self, platform: str, scope: str, scope_value: str
) -&gt; bool:
    &quot;&quot;&quot;Remove a binding. Returns True if a row was deleted.&quot;&quot;&quot;
    def _do(conn):
        cur = conn.execute(
            &quot;DELETE FROM profile_bindings &quot;
            &quot;WHERE platform = ? AND scope = ? AND scope_value = ?&quot;,
            (platform, scope, scope_value),
        )
        return cur.rowcount &gt; 0
    return self._execute_write(_do)
