Step 1: Write the full module
&quot;&quot;&quot;
Profile router for multi-profile Gateway support.

Resolves which profile should handle a given message and loads per-profile
configuration from ~/.intellect/profiles/&lt;name&gt;/config.yaml.
&quot;&quot;&quot;
from __future__ import annotations

import logging
import os
from copy import deepcopy
from pathlib import Path
from typing import Any, Dict, Optional

from intellect_cli.profiles import get_profile_dir
from intellect_constants import get_intellect_home

logger = logging.getLogger(__name__)


# Optional import — only needed when multi_profile is enabled.
try:
    import yaml
except ImportError:
    yaml = None  # type: ignore


def _deep_merge(base: dict, override: dict) -&gt; dict:
    &quot;&quot;&quot;Recursively merge *override* into *base*.  Override wins.&quot;&quot;&quot;
    merged = deepcopy(base)
    for key, value in override.items():
        if key in merged and isinstance(merged[key], dict) and isinstance(value, dict):
            merged[key] = _deep_merge(merged[key], value)
        else:
            merged[key] = deepcopy(value)
    return merged


def _load_profile_config(profile_name: str) -&gt; Dict[str, Any]:
    &quot;&quot;&quot;Load config.yaml for a named profile, or return {} on any error.&quot;&quot;&quot;
    profile_dir = get_profile_dir(profile_name)
    config_path = profile_dir / &quot;config.yaml&quot;
    if not config_path.is_file():
        logger.debug(&quot;No config.yaml for profile %r at %s&quot;, profile_name, config_path)
        return {}
    if yaml is None:
        logger.warning(&quot;PyYAML not installed — cannot load profile config for %r&quot;, profile_name)
        return {}
    try:
        with open(config_path, &quot;r&quot;, encoding=&quot;utf-8&quot;) as fh:
            return yaml.safe_load(fh) or {}
    except Exception as exc:
        logger.warning(&quot;Failed to load config.yaml for profile %r: %s&quot;, profile_name, exc)
        return {}


class ProfileRouter:
    &quot;&quot;&quot;Resolve and cache per-profile configuration within a Gateway process.&quot;&quot;&quot;

    def __init__(self, *, enabled: bool = False, default_profile: str = &quot;default&quot;):
        self._enabled = enabled
        self._default_profile = default_profile
        # profile_name → merged config dict (lazy, cached forever)
        self._config_cache: Dict[str, Dict[str, Any]] = {}

    @property
    def enabled(self) -&gt; bool:
        return self._enabled

    # ── resolution ───────────────────────────────────────────────────────

    def resolve(
        self,
        *,
        platform: str,
        user_id: Optional[str] = None,
        chat_id: Optional[str] = None,
    ) -&gt; str:
        &quot;&quot;&quot;Return the profile name that should handle this message.

        Resolution order (first match wins):
        1. Per-user binding  (`profile_bindings` scope=&#039;user&#039;)
        2. Per-chat binding  (`profile_bindings` scope=&#039;chat&#039;)
        3. Gateway&#039;s default profile  (multi_profile.default_profile)

        When ``enabled`` is False, always returns ``&quot;default&quot;``.
        &quot;&quot;&quot;
        if not self._enabled:
            return &quot;default&quot;

        # Lazy import to avoid pulling state.db at module load.
        from intellect_state import SessionDB

        try:
            session_db = SessionDB()
        except Exception:
            logger.debug(&quot;SessionDB unavailable — falling back to default profile&quot;)
            return self._default_profile

        try:
            # 1. Per-user binding
            if user_id:
                binding = session_db.get_profile_binding(platform, &quot;user&quot;, user_id)
                if binding:
                    return binding

            # 2. Per-chat binding
            if chat_id:
                binding = session_db.get_profile_binding(platform, &quot;chat&quot;, chat_id)
                if binding:
                    return binding
        except Exception:
            logger.debug(&quot;profile_bindings query failed&quot;, exc_info=True)
        finally:
            try:
                session_db.close()
            except Exception:
                pass

        # 3. Fallback
        return self._default_profile

    # ── config loading ────────────────────────────────────────────────────

    def get_profile_config(
        self,
        profile_name: str,
        base_config: Dict[str, Any],
    ) -&gt; Dict[str, Any]:
        &quot;&quot;&quot;Return the merged config for *profile_name*.

        On first access, loads the profile&#039;s ``config.yaml`` and merges it
        into *base_config* (the Gateway&#039;s own config).  Result is cached.
        &quot;&quot;&quot;
        if profile_name in self._config_cache:
            return self._config_cache[profile_name]

        profile_config = _load_profile_config(profile_name)
        merged = _deep_merge(base_config, profile_config)
        self._config_cache[profile_name] = merged
        logger.info(
            &quot;Loaded profile %r config (%d top-level keys from config.yaml)&quot;,
            profile_name, len(profile_config),
        )
        return merged

    def get_profile_intellect_home(self, profile_name: str) -&gt; Path:
        &quot;&quot;&quot;Return the INTELLECT_HOME for a profile.

        For the default profile, returns ``get_intellect_home()``.
        For named profiles, returns ``~/.intellect/profiles/&lt;name&gt;/``.
        &quot;&quot;&quot;
        if profile_name == &quot;default&quot;:
            return get_intellect_home()
        return get_profile_dir(profile_name)
